#include <iostream>
using namespace std;

// Default arguments in function declaration
void display(int a = 10, int b = 20, int c = 30) {
 cout << "a=" << a << ", b=" << b << ", c=" << c << endl;
}

int main() {
 display(); // Uses all defaults: 10,20,30
 display(5); // a=5, uses b=20, c=30
 display(5, 15); // a=5, b=15, uses c=30
 display(5, 15, 25); // All provided: 5,15,25

 return 0;
}

#include <iostream>
using namespace std;

class Rectangle {
private:
 float length, breadth;
public:
 // Constructor with default arguments
 Rectangle(float l = 1.0, float b = 1.0) {
 length = l;
 breadth = b;
 }

 float area() {
 return length * breadth;
 }

 void display() {
 cout << "Length: " << length ", Breadth: " << breadth << endl;
 }
};

int main() {
 Rectangle r1; // Uses defaults: 1.0, 1.0
 Rectangle r2(5); // Length=5, breadth=1.0
 Rectangle r3(5, 3); // Length=5, breadth=3

 r1.display(); cout << "Area: " << r1.area() << endl;
 r2.display(); cout << "Area: " << r2.area() << endl;
 r3.display(); cout << "Area: " << r3.area() << endl;

 return 0;
}

#include <iostream>
using namespace std;

// Approach 1: Using Default Arguments
void printInfo(string name = "Unknown", int age = 0) {
 cout << "Name: " << name << ", Age: " << age << endl;
}

// Approach 2: Using Function Overloading
void printInfo(string name) {
 cout << "Name: " << name << ", Age: " << 0 << endl;
}

void printInfo(string name, int age) {
 cout << "Name: " << name << ", Age: " << age << endl;
}

int main() {
 // Default arguments approach - single function
 printInfo();
 printInfo("Alice");
 printInfo("Bob", 25);

 // Note: Cannot have both approaches in same program
 // as it causes ambiguity

 return 0;
}

