#include <iostream>
#include <string>
using namespace std;

string formatName(string firstName, 
 string lastName = "", 
 string title = "Mr.") {
 if (lastName.empty()) {
 return title + " " + firstName;
 }
 return title + " " + firstName + " " + lastName;
}

int main() {
 // Various ways to call the function
 cout << formatName("John") << endl; // Uses both defaults
 cout << formatName("John", "Doe") << endl; // Uses title default
 cout << formatName("John", "Doe", "Dr.") << endl; // No defaults
 cout << formatName("Jane", "", "Ms.") << endl; // Explicit empty lastName

 return 0;
}
